mapper.sql:
select d.delivery_id, d.delivery_date, d.route_id, r.route_name, d.total_amount, d.status, d.create_time, d.remark
from (
    select * from biz_delivery_order ${ew.getCustomSqlSegment}
) d
left join biz_route r on d.route_id = r.route_id
order by d.delivery_date desc, d.delivery_id desc
